    10→/// Represents an operation that can be queued for later execution
    11→abstract class QueueableOperation {
    12→  /// Unique identifier for the operation
    13→  String get id;
    14→
    15→  /// Type of operation for grouping and processing
    16→  String get type;
    17→
    18→  /// Priority of the operation (higher number = higher priority)
    19→  int get priority;
    20→
    21→  /// Whether this operation requires an active network connection
    22→  bool get requiresNetwork;
    23→
    24→  /// Execute the operation
    25→  Future<void> execute();
    26→
    27→  /// Convert operation to JSON for persistence
    28→  Map<String, dynamic> toJson();
    29→}
    30→
    31→@riverpod
    32→class OperationQueue extends _$OperationQueue {
    33→  final Queue<QueueableOperation> _pendingOperations = Queue();
    34→  Timer? _processingTimer;
    35→  bool _isProcessing = false;
    36→
    37→  @override
    38→  Future<void> build() async {
    39→    // Watch connectivity and token state
    40→    ref.watch(connectivityNotifierProvider);
    41→    ref.watch(tokenManagerProvider);
    42→
    43→    // Setup periodic processing
    44→    _setupProcessing();
    45→
    46→    // Clean up on dispose
    47→    ref.onDispose(() {
    48→      _processingTimer?.cancel();
    49→    });
    50→  }
    51→
    52→  void _setupProcessing() {
    53→    _processingTimer?.cancel();
    54→    _processingTimer = Timer.periodic(
    55→      const Duration(seconds: 30),
    56→      (_) => processQueue(),
    57→    );
    58→  }
    59→
    60→  /// Add an operation to the queue
    61→  Future<void> addOperation(QueueableOperation operation) async {
    62→    _pendingOperations.add(operation);
    63→    await _persistQueue();
    64→
    65→    // Try to process immediately if conditions are right
    66→    if (_canProcess(operation)) {
    67→      processQueue();
    68→    }
    69→  }
    70→
    71→  /// Process all operations in the queue that can be executed
    72→  Future<void> processQueue() async {
    73→    if (_isProcessing) return;
    74→    _isProcessing = true;
    75→
    76→    try {
    77→      final tokenManager = ref.read(tokenManagerProvider);
    78→      final isOnline = ref.read(connectivityNotifierProvider);
    79→
    80→      // Process operations in priority order
    81→      final operations = _pendingOperations.toList()
    82→        ..sort((a, b) => b.priority.compareTo(a.priority));
    83→
    84→      for (final operation in operations) {
    85→        if (!_canProcess(operation)) continue;
    86→
    87→        try {
    88→          await operation.execute();
    89→          _pendingOperations.remove(operation);
    90→        } catch (e) {
    91→          debugPrint('Failed to execute operation ${operation.id}: $e');
    92→          // Leave operation in queue for retry
    93→        }
    94→      }
    95→
    96→      await _persistQueue();
    97→    } finally {
    98→      _isProcessing = false;
    99→    }
   100→  }
   101→
   102→  bool _canProcess(QueueableOperation operation) {
   103→    final tokenManager = ref.read(tokenManagerProvider);
   104→    final isOnline = ref.read(connectivityNotifierProvider);
   105→
   106→    if (operation.requiresNetwork) {
   107→      return isOnline && tokenManager.canPerformOnlineOperations;
   108→    }
   109→
   110→    return tokenManager.hasValidTokens;
   111→  }
   112→
   113→  Future<void> _persistQueue() async {
   114→    // TODO: Implement queue persistence
   115→    // This would save the queue to local storage for recovery after app restart
   116→  }
   117→}
